mapper.update:
UPDATE SUPFUSION_I18N_RESOURCE

    MODIFY_TIME = #{modifyTime}

WHERE I18N_KEY = #{i18nKey} AND VALID = '1'

mapper.select:
SELECT I18N_KEY FROM(
SELECT rownum seq,I18N_KEY FROM(
SELECT I18N_KEY,MAX(MODIFY_TIME) from (SELECT I18N_KEY,MODIFY_TIME FROM SUPFUSION_I18N_RESOURCE  WHERE
VALID = '1'

    AND I18N_KEY LIKE CONCAT('%',CONCAT(#{i18n_key},'%'))


    AND LANGU_CODE = #{langu_code} AND I18N_VALUE LIKE CONCAT('%',CONCAT(#{i18n_value},'%'))
) GROUP BY
I18N_KEY ORDER BY MAX(MODIFY_TIME) DESC,I18N_KEY DESC
)
)t1 


WHERE t1.seq >= #{rowStart} AND t1.seq <= #{rowOver}

SELECT I18N_KEY FROM(
select rownum seq,I18N_KEY FROM(
select I18N_KEY,MAX(MODIFY_TIME) from (SELECT I18N_KEY,MODIFY_TIME FROM SUPFUSION_I18N_RESOURCE WHERE
VALID = '1'

    AND I18N_KEY LIKE CONCAT('%',CONCAT(#{i18n_key},'%'))


    AND I18N_VALUE LIKE CONCAT('%',CONCAT(#{i18n_value},'%'))
)  group by I18N_KEY order by MAX(MODIFY_TIME) desc,I18N_KEY desc
)
)t1



    WHERE t1.seq >= #{rowStart} AND t1.seq <= #{rowOver}

SELECT I18N_KEY FROM(
SELECT rownum seq,I18N_KEY FROM(
SELECT I18N_KEY,MAX(MODIFY_TIME) FROM (
SELECT I18N_KEY,MODIFY_TIME FROM SUPFUSION_I18N_RESOURCE
WHERE
SUPFUSION_I18N_RESOURCE.VALID = '1'
AND

    I18N_KEY LIKE CONCAT('%',CONCAT(#{i18n_key},'%'))  ESCAPE '\'

)  GROUP BY I18N_KEY ORDER BY MAX(MODIFY_TIME) DESC,I18N_KEY DESC
)
)t1



WHERE t1.seq >= #{rowStart} AND t1.seq <= #{rowOver}

